#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline LL Min(LL x,LL y){return x<y?x:y;}
const int N=2e5+10;
struct Tree{int l,r;}t[N];
LL f[N][20],g[N][20],a[N],dis[N][20],ans=4e18;
int main()
{
//	freopen("data.txt","r",stdin);
//	freopen("mine.txt","w",stdout);
	int n=read();rep(1,n,i)a[i]=read();
	rep(1,n,i)
	{
		if((i<<1)<=n)t[i].l=i<<1;
		if((i<<1|1)<=n)t[i].r=i<<1|1;
	}
	rep(2,n,i){dis[i][1]=read();}
	rep(1,n,i)rep(2,18,j)dis[i][j]=dis[i][j-1]+dis[i>>(j-1)][1];
	drep(n,1,u)
	{
		if(!t[u].l)for(int i=1;u>>(i-1);++i)
		{
			int kfa=((u>>(i-1))^1);
			g[u][i]=(dis[u][i]+dis[kfa][1])*a[kfa];
		}
		else if(!t[u].r)for(int i=1;u>>(i-1);++i)g[u][i]=dis[t[u].l][1]*a[t[u].l]+g[t[u].l][i+1];
		else for(int i=1;u>>(i-1);++i)
		{
			g[u][i]=Min(dis[t[u].l][1]*a[t[u].l]+g[t[u].l][1]+g[t[u].r][i+1],
						dis[t[u].r][1]*a[t[u].r]+g[t[u].r][1]+g[t[u].l][i+1]);
		}
	}
	
	drep(n,1,u)
	{
		if(!t[u].l)for(int i=1;u>>(i-1);++i)f[u][i]=dis[u][i]*a[u>>i];
		else if(!t[u].r)for(int i=1;u>>(i-1);++i)f[u][i]=f[t[u].l][i+1]+dis[t[u].l][1]*a[t[u].l];
		else for(int i=1;u>>(i-1);++i)
		{
			f[u][i]=Min(dis[t[u].l][1]*a[t[u].l]+g[t[u].l][1]+f[t[u].r][i+1],
						dis[t[u].r][1]*a[t[u].r]+g[t[u].r][1]+f[t[u].l][i+1]);
		}
	}
	rep(1,n,u)
	{
		LL tmp=f[u][1];for(int i=1,cur=u>>1;cur;++i,cur=cur>>1)
		{
			int kfa=(u>>(i-1))^1;
			if(kfa>n)tmp+=dis[cur][1]*a[cur>>1];
			else tmp+=dis[kfa][1]*a[kfa]+f[kfa][2];
		}
//		printf("%d :: %lld\n",u,tmp);
		ans=Min(ans,tmp);
	}
	printf("%lld\n",ans);return 0;
}
